119: protected:
120:   class WatchImpl : public Envoy::Config::GrpcMuxWatch {
121:   public:
122:     WatchImpl(const std::string& type_url, Watch* watch, GrpcMuxImpl& parent,
123:               const SubscriptionOptions& options)
124:         : type_url_(type_url), watch_(watch), parent_(parent), options_(options) {}
125: 
126:     ~WatchImpl() override { remove(); }
127: 
128:     void remove() {
129:       if (watch_) {
130:         parent_.removeWatch(type_url_, watch_);
131:         watch_ = nullptr;
132:       }
133:     }
134: 
135:     void update(const absl::flat_hash_set<std::string>& resources) override {
136:       parent_.updateWatch(type_url_, watch_, resources, options_);
137:     }
138: 
139:   private:
140:     const std::string type_url_;
141:     Watch* watch_;
142:     GrpcMuxImpl& parent_;
143:     const SubscriptionOptions options_;
144:   };
145: 
146:   void sendGrpcMessage(RQ& msg_proto, S& sub_state);
147:   void maybeUpdateQueueSizeStat(uint64_t size) { grpc_stream_->maybeUpdateQueueSizeStat(size); }
148:   bool grpcStreamAvailable() { return grpc_stream_->grpcStreamAvailable(); }
149:   bool rateLimitAllowsDrain() { return grpc_stream_->checkRateLimitAllowsDrain(); }
150:   void sendMessage(RQ& msg_proto) { grpc_stream_->sendMessage(msg_proto); }
151: 
152:   S& subscriptionStateFor(const std::string& type_url);
153:   WatchMap& watchMapFor(const std::string& type_url);
154:   void handleEstablishedStream();
155:   void handleStreamEstablishmentFailure();
156:   void genericHandleResponse(const std::string& type_url, const RS& response_proto,
157:                              ControlPlaneStats& control_plane_stats);
158:   void trySendDiscoveryRequests();
159:   bool skipSubsequentNode() const { return skip_subsequent_node_; }
160:   bool anyRequestSentYetInCurrentStream() const { return any_request_sent_yet_in_current_stream_; }
161:   void setAnyRequestSentYetInCurrentStream(bool value) {
162:     any_request_sent_yet_in_current_stream_ = value;
163:   }
164:   const LocalInfo::LocalInfo& localInfo() const { return local_info_; }
165: 
166: private:
167:   // Helper function to create the grpc_stream_ object.
168:   // TODO(adisuissa): this should be removed when envoy.restart_features.xds_failover_support
169:   // is deprecated.
170:   std::unique_ptr<GrpcStreamInterface<RQ, RS>>
171:   createGrpcStreamObject(GrpcMuxContext& grpc_mux_context);
172: 
173:   // Checks whether external conditions allow sending a DeltaDiscoveryRequest. (Does not check
174:   // whether we *want* to send a (Delta)DiscoveryRequest).
175:   bool canSendDiscoveryRequest(const std::string& type_url);
176: 
177:   // Checks whether we have something to say in a (Delta)DiscoveryRequest, which can be an ACK
178:   // and/or a subscription update. (Does not check whether we *can* send that
179:   // (Delta)DiscoveryRequest). Returns the type_url we should send the DeltaDiscoveryRequest for (if
180:   // any). First, prioritizes ACKs over non-ACK subscription interest updates. Then, prioritizes
181:   // non-ACK updates in the order the various types of subscriptions were activated (as tracked by
182:   // subscription_ordering_).
183:   absl::optional<std::string> whoWantsToSendDiscoveryRequest();
184: 
185:   // Invoked when dynamic context parameters change for a resource type.
186:   void onDynamicContextUpdate(absl::string_view resource_type_url);
187: 
188:   // Multiplexes the stream to the primary and failover sources.
189:   // TODO(adisuissa): Once envoy.restart_features.xds_failover_support is deprecated,
190:   // convert from unique_ptr<GrpcStreamInterface> to GrpcMuxFailover directly.
191:   std::unique_ptr<GrpcStreamInterface<RQ, RS>> grpc_stream_;
192: 
193:   // Resource (N)ACKs we're waiting to send, stored in the order that they should be sent in. All
194:   // of our different resource types' ACKs are mixed together in this queue. See class for
195:   // description of how it interacts with pause() and resume().
196:   PausableAckQueue pausable_ack_queue_;
197: 
198:   // Makes SubscriptionStates, to be held in the subscriptions_ map. Whether this GrpcMux is doing
199:   // delta or state of the world xDS is determined by which concrete subclass this variable gets.
200:   std::unique_ptr<F> subscription_state_factory_;
201: 
202:   // Map key is type_url.
203:   // Only addWatch() should insert into these maps.
204:   absl::flat_hash_map<std::string, std::unique_ptr<S>> subscriptions_;
205:   absl::flat_hash_map<std::string, std::unique_ptr<WatchMap>> watch_maps_;
206: 
207:   // Determines the order of initial discovery requests. (Assumes that subscriptions are added
208:   // to this GrpcMux in the order of Envoy's dependency ordering).
209:   std::list<std::string> subscription_ordering_;
210: 
211:   // Whether to enable the optimization of only including the node field in the very first
212:   // discovery request in an xDS gRPC stream (really just one: *not* per-type_url).
213:   const bool skip_subsequent_node_;
214: 
215:   // State to help with skip_subsequent_node's logic.
216:   bool any_request_sent_yet_in_current_stream_{};
217: 
218:   // Used to populate the (Delta)DiscoveryRequest's node field. That field is the same across
219:   // all type_urls, and moreover, the 'skip_subsequent_node' logic needs to operate across all
220:   // the type_urls. So, while the SubscriptionStates populate every other field of these messages,
221:   // this one is up to GrpcMux.
222:   const LocalInfo::LocalInfo& local_info_;
223:   Common::CallbackHandlePtr dynamic_update_callback_handle_;
224:   CustomConfigValidatorsPtr config_validators_;
225:   XdsConfigTrackerOptRef xds_config_tracker_;
226:   XdsResourcesDelegateOptRef xds_resources_delegate_;
227:   EdsResourcesCachePtr eds_resources_cache_;
228:   const std::string target_xds_authority_;
229: 
230:   bool started_{false};
231:   // True iff Envoy is shutting down; no messages should be sent on the `grpc_stream_` when this is
232:   // true because it may contain dangling pointers.
233:   std::atomic<bool> shutdown_{false};
234: };
