136: template <class T> class SubscriptionStateFactory {
137: public:
138:   virtual ~SubscriptionStateFactory() = default;
139:   // Note that, outside of tests, we expect callbacks to always be a WatchMap.
140:   virtual std::unique_ptr<T>
